// Static — cached indefinitely
async function getStaticData() {
    return fetch('https://api.example.com/config', { cache: 'force-cache' }).then(r => r.json());
}

// Dynamic — never cached
async function getDynamicData() {
    return fetch('https://api.example.com/live', { cache: 'no-store' }).then(r => r.json());
}

// ISR — revalidate every 60 seconds
async function getRevalidatedData() {
    return fetch('https://api.example.com/posts', { next: { revalidate: 60 } }).then(r => r.json());
}

export default async function Page() {
    const [config, live, posts] = await Promise.all([
        getStaticData(), getDynamicData(), getRevalidatedData(),
    ]);
    return <pre>{JSON.stringify({ config, live, posts }, null, 2)}</pre>;
}

'use client';

import { useOptimistic, useTransition } from 'react';
import { toggleLike } from './actions';

interface Post { id: number; likes: number; liked: boolean; }

export default function LikeButton({ post }: { post: Post }) {
    const [, startTransition] = useTransition();
    const [optimisticPost, addOptimistic] = useOptimistic(
        post,
        (state, liked: boolean) => ({
            ...state,
            liked,
            likes: liked ? state.likes + 1 : state.likes - 1,
        })
    );

    function handleClick() {
        startTransition(async () => {
            addOptimistic(!optimisticPost.liked);
            await toggleLike(post.id);
        });
    }

    return (
        <button onClick={handleClick}>
            {optimisticPost.liked ? '♥' : '♡'} {optimisticPost.likes}
        </button>
    );
}

