export default async function PostsPage() {
    const posts = await getPosts();
    return <ul>{posts.map((p: { id: number; title: string }) => <li key={p.id}>{p.title}</li>)}</ul>;
}

// Webhook handler triggers revalidation
export async function POST(req: NextRequest) {
    const secret = req.headers.get('x-webhook-secret');
    if (secret !== process.env.WEBHOOK_SECRET) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }
    revalidateTag('posts');
    return NextResponse.json({ revalidated: true });
}

import { notFound } from 'next/navigation';

async function fetchUser(id: string) {
    const res = await fetch(`https://api.example.com/users/${id}`, { next: { revalidate: 300 } });
    if (res.status === 404) notFound();
    if (!res.ok) throw new Error(`User fetch failed: ${res.status}`);
    return res.json();
}

async function fetchUserPosts(id: string) {
    const res = await fetch(`https://api.example.com/users/${id}/posts`, { next: { revalidate: 60 } });
    if (!res.ok) return [];
    return res.json();
}

export default async function ProfilePage({ params }: { params: { id: string } }) {
    const [user, posts] = await Promise.all([
        fetchUser(params.id),
        fetchUserPosts(params.id),
    ]);

    return (
        <div>
            <h1>{user.name}</h1>
            <p>{posts.length} posts</p>
        </div>
    );
}
